"use client"

import React from "react";
import { Swiper, SwiperSlide, useSwiper } from 'swiper/react';
import { Navigation, Pagination, Scrollbar, A11y, Autoplay } from 'swiper/modules';
import clsx from "clsx";

const HomeSlider = () => {
  return (
    <Swiper
        className="home-slider"
        modules={[ Navigation, Autoplay ]}
        spaceBetween={30}
        speed={1200}
        // centeredSlides={true}
        loop={true}
        autoplay={{
            delay: 3500,
            pauseOnMouseEnter: true,
            waitForTransition: true,
            stopOnLastSlide: false
        }}
        navigation={false}
        onRealIndexChange={(swiper) => {
            console.log("Current slide index:", swiper.realIndex);
        }
        }
    >
        <SlideButton type={"prev"} text={"Prev"} />
      <SwiperSlide>
        Slide 1
      </SwiperSlide>
      <SwiperSlide>
        Slide 2
      </SwiperSlide>
      <SwiperSlide>
        Slide 3
      </SwiperSlide>
      <SlideButton type={"next"} text={"Next"} />
    </Swiper>
  );
}

function SlideButton({type, className, text}) {
  const swiper = useSwiper();
  const onClick = () => {
    if(type === "next") {
      swiper.slideNext();
    } else {
      swiper.slidePrev();
    }
  }

  return <div className={clsx(className, "slide-button", "unselectable")} onClick={onClick}>
    {text}
  </div>
}

export default HomeSlider;